  ;(['helpers', 'components', 'directives'] as const).forEach(key => {
    childContext[key].forEach((value: any, helperKey: any) => {
      if (key === 'helpers') {
        const parentCount = parentContext.helpers.get(helperKey)
        if (parentCount === undefined) {
          parentContext.helpers.set(helperKey, value)
        } else {
          parentContext.helpers.set(helperKey, value + parentCount)
        }
      } else {
        ;(parentContext[key] as any).add(value)
      }
    })
  })
  // imports/hoists are not merged because:
  // - imports are only used for asset urls and should be consistent between
  //   node/client branches
  // - hoists are not enabled for the client branch here
}

  if (isArray(v)) {
    return v.map(clone)
  } else if (isPlainObject(v)) {
    const res: any = {}
    for (const key in v) {
      res[key] = clone(v[key as keyof typeof v])
    }
    return res
  } else {
    return v
  }
}

  // element
  // generate the template literal representing the open tag.
  const openTag: TemplateLiteral['elements'] = [`<${node.tag}`]
  // some tags need to be passed to runtime for special checks
  const needTagForRuntime =
    node.tag === 'textarea' || node.tag.indexOf('-') > 0

  // v-bind="obj", v-bind:[key] and custom directives can potentially
  // overwrite other static attrs and can affect final rendering result,
  // so when they are present we need to bail out to full `renderAttrs`
  const hasDynamicVBind = hasDynamicKeyVBind(node)
  const hasCustomDir = node.props.some(
    p => p.type === NodeTypes.DIRECTIVE && !isBuiltInDirective(p.name),
  )

  // v-show has a higher priority in ssr
  const vShowPropIndex = node.props.findIndex(
    i => i.type === NodeTypes.DIRECTIVE && i.name === 'show',
  )
  if (vShowPropIndex !== -1) {
    const vShowProp = node.props[vShowPropIndex]
    node.props.splice(vShowPropIndex, 1)
    node.props.push(vShowProp)
  }

  const needMergeProps = hasDynamicVBind || hasCustomDir
  if (needMergeProps) {
    const { props, directives } = buildProps(
      node,
      context,
      node.props,
      false /* isComponent */,
      false /* isDynamicComponent */,
      true /* ssr */,
    )
    if (props || directives.length) {
      const mergedProps = buildSSRProps(props, directives, context)
      const propsExp = createCallExpression(
        context.helper(SSR_RENDER_ATTRS),
        [mergedProps],
      )

      if (node.tag === 'textarea') {
        const existingText = node.children[0] as
          | TextNode
          | InterpolationNode
          | undefined
        // If interpolation, this is dynamic <textarea> content, potentially
        // injected by v-model and takes higher priority than v-bind value.
        // Additionally, directives with content overrides (v-text/v-html)
        // have higher priority than the merged props.
        if (
          !hasContentOverrideDirective(node) &&
          (!existingText || existingText.type !== NodeTypes.INTERPOLATION)
        ) {
          // <textarea> with dynamic v-bind. We don't know if the final props
          // will contain .value, so we will have to do something special:
          // assign the merged props to a temp variable, and check whether
          // it contains value (if yes, render is as children).
          const tempId = `_temp${context.temps++}`
          propsExp.arguments = [
            createAssignmentExpression(
              createSimpleExpression(tempId, false),
              mergedProps,
            ),
          ]
          rawChildrenMap.set(
            node,
            createCallExpression(context.helper(SSR_INTERPOLATE), [
              createConditionalExpression(
                createSimpleExpression(`"value" in ${tempId}`, false),
                createSimpleExpression(`${tempId}.value`, false),
                createSimpleExpression(
                  existingText ? existingText.content : ``,
                  true,
                ),
                false,
              ),
            ]),
          )
        }
      } else if (node.tag === 'input') {
        // <input v-bind="obj" v-model>
        // we need to determine the props to render for the dynamic v-model
        // and merge it with the v-bind expression.
        const vModel = findVModel(node)
        if (vModel) {
          // 1. save the props (san v-model) in a temp variable
          const tempId = `_temp${context.temps++}`
          const tempExp = createSimpleExpression(tempId, false)
          propsExp.arguments = [
            createSequenceExpression([
              createAssignmentExpression(tempExp, mergedProps),
              createCallExpression(context.helper(MERGE_PROPS), [
                tempExp,
                createCallExpression(
                  context.helper(SSR_GET_DYNAMIC_MODEL_PROPS),
                  [
                    tempExp, // existing props
                    vModel.exp!, // model
                  ],
                ),
              ]),
            ]),
          ]
        }
      } else if (directives.length && !node.children.length) {
        // v-text/v-html have higher priority than the merged props
        if (!hasContentOverrideDirective(node)) {
          const tempId = `_temp${context.temps++}`
          propsExp.arguments = [
            createAssignmentExpression(
              createSimpleExpression(tempId, false),
              mergedProps,
            ),
          ]
          rawChildrenMap.set(
            node,
            createConditionalExpression(
              createSimpleExpression(`"textContent" in ${tempId}`, false),
              createCallExpression(context.helper(SSR_INTERPOLATE), [
                createSimpleExpression(`${tempId}.textContent`, false),
              ]),
              createSimpleExpression(`${tempId}.innerHTML ?? ''`, false),
              false,
            ),
          )
        }
      }

      if (needTagForRuntime) {
        propsExp.arguments.push(`"${node.tag}"`)
      }

      openTag.push(propsExp)
    }
  }

  // book keeping static/dynamic class merging.
  let dynamicClassBinding: CallExpression | undefined = undefined
  let staticClassBinding: string | undefined = undefined
  // all style bindings are converted to dynamic by transformStyle.
  // but we need to make sure to merge them.
  let dynamicStyleBinding: CallExpression | undefined = undefined

  for (let i = 0; i < node.props.length; i++) {
    const prop = node.props[i]
    // ignore true-value/false-value on input
    if (node.tag === 'input' && isTrueFalseValue(prop)) {
      continue
    }
    // special cases with children override
    if (prop.type === NodeTypes.DIRECTIVE) {
      if (prop.name === 'html' && prop.exp) {
        rawChildrenMap.set(
          node,
          createCompoundExpression([`(`, prop.exp, `) ?? ''`]),
        )
      } else if (prop.name === 'text' && prop.exp) {
        node.children = [createInterpolation(prop.exp, prop.loc)]
      } else if (prop.name === 'slot') {
        context.onError(
          createCompilerError(ErrorCodes.X_V_SLOT_MISPLACED, prop.loc),
        )
      } else if (isTextareaWithValue(node, prop) && prop.exp) {
        if (!needMergeProps) {
          node.children = [createInterpolation(prop.exp, prop.loc)]
        }
      } else if (!needMergeProps && prop.name !== 'on') {
        // Directive transforms.
        const directiveTransform = context.directiveTransforms[prop.name]
        if (directiveTransform) {
          const { props, ssrTagParts } = directiveTransform(
            prop,
            node,
            context,
          )
          if (ssrTagParts) {
            openTag.push(...ssrTagParts)
          }
          for (let j = 0; j < props.length; j++) {
            const { key, value } = props[j]
            if (isStaticExp(key)) {
              let attrName = key.content
              // static key attr
              if (attrName === 'key' || attrName === 'ref') {
                continue
              }
              if (attrName === 'class') {
                openTag.push(
                  ` class="`,
                  (dynamicClassBinding = createCallExpression(
                    context.helper(SSR_RENDER_CLASS),
                    [value],
                  )),
                  `"`,
                )
              } else if (attrName === 'style') {
                if (dynamicStyleBinding) {
                  // already has style binding, merge into it.
                  mergeCall(dynamicStyleBinding, value)
                } else {
                  openTag.push(
                    ` style="`,
                    (dynamicStyleBinding = createCallExpression(
                      context.helper(SSR_RENDER_STYLE),
                      [value],
                    )),
                    `"`,
                  )
                }
              } else {
                attrName =
                  node.tag.indexOf('-') > 0
                    ? attrName // preserve raw name on custom elements
                    : propsToAttrMap[attrName] || attrName.toLowerCase()
                if (isBooleanAttr(attrName)) {
                  openTag.push(
                    createConditionalExpression(
                      createCallExpression(
                        context.helper(SSR_INCLUDE_BOOLEAN_ATTR),
                        [value],
                      ),
                      createSimpleExpression(' ' + attrName, true),
                      createSimpleExpression('', true),
                      false /* no newline */,
                    ),
                  )
                } else if (isSSRSafeAttrName(attrName)) {
                  openTag.push(
                    createCallExpression(context.helper(SSR_RENDER_ATTR), [
                      key,
                      value,
                    ]),
                  )
                } else {
                  context.onError(
                    createSSRCompilerError(
                      SSRErrorCodes.X_SSR_UNSAFE_ATTR_NAME,
                      key.loc,
                    ),
                  )
                }
              }
            } else {
              // dynamic key attr
              // this branch is only encountered for custom directive
              // transforms that returns properties with dynamic keys
              const args: CallExpression['arguments'] = [key, value]
              if (needTagForRuntime) {
                args.push(`"${node.tag}"`)
              }
              openTag.push(
                createCallExpression(
                  context.helper(SSR_RENDER_DYNAMIC_ATTR),
                  args,
                ),
              )
            }
          }
        }
      }
    } else {
      // special case: value on <textarea>
      const name = prop.name
      if (node.tag === 'textarea' && name === 'value' && prop.value) {
        rawChildrenMap.set(node, escapeHtml(prop.value.content))
      } else if (!needMergeProps) {
        if (name === 'key' || name === 'ref') {
          continue
        }
        // static prop
        if (name === 'class' && prop.value) {
          staticClassBinding = JSON.stringify(prop.value.content)
        }
        openTag.push(
          ` ${prop.name}` +
            (prop.value ? `="${escapeHtml(prop.value.content)}"` : ``),
        )
      }
    }
  }

  // handle co-existence of dynamic + static class bindings
  if (dynamicClassBinding && staticClassBinding) {
    mergeCall(dynamicClassBinding, staticClassBinding)
    removeStaticBinding(openTag, 'class')
  }

  if (context.scopeId) {
    openTag.push(` ${context.scopeId}`)
  }

  node.ssrCodegenNode = createTemplateLiteral(openTag)
}

  let mergePropsArgs: JSChildNode[] = []
  if (props) {
    if (props.type === NodeTypes.JS_CALL_EXPRESSION) {
      // already a mergeProps call
      mergePropsArgs = props.arguments as JSChildNode[]
    } else {
      mergePropsArgs.push(props)
    }
  }
  if (directives.length) {
    for (const dir of directives) {
      mergePropsArgs.push(
        createCallExpression(context.helper(SSR_GET_DIRECTIVE_PROPS), [
          `_ctx`,
          ...buildDirectiveArgs(dir, context).elements,
        ] as JSChildNode[]),
      )
    }
  }

  return mergePropsArgs.length > 1
    ? createCallExpression(context.helper(MERGE_PROPS), mergePropsArgs)
    : mergePropsArgs[0]
}

  if (prop.type === NodeTypes.DIRECTIVE) {
    return (
      prop.name === 'bind' &&
      prop.arg &&
      isStaticExp(prop.arg) &&
      (prop.arg.content === 'true-value' || prop.arg.content === 'false-value')
    )
  } else {
    return prop.name === 'true-value' || prop.name === 'false-value'
  }
}

  return !!(
    node.tag === 'textarea' &&
    prop.name === 'bind' &&
    isStaticArgOf(prop.arg, 'value')
  )
}

  const existing = call.arguments[0] as ExpressionNode | ArrayExpression
  if (existing.type === NodeTypes.JS_ARRAY_EXPRESSION) {
    existing.elements.push(arg)
  } else {
    call.arguments[0] = createArrayExpression([existing, arg])
  }
}

  const regExp = new RegExp(`^ ${binding}=".+"$`)

  const i = tag.findIndex(e => typeof e === 'string' && regExp.test(e))

  if (i > -1) {
    tag.splice(i, 1)
  }
}

  return node.props.find(
    p => p.type === NodeTypes.DIRECTIVE && p.name === 'model' && p.exp,
  ) as DirectiveNode | undefined
}

  const isVoidTag = context.options.isVoidTag || NO
  const elementsToAdd = node.ssrCodegenNode!.elements
  for (let j = 0; j < elementsToAdd.length; j++) {
    context.pushStringPart(elementsToAdd[j])
  }

  // Handle slot scopeId
  if (context.withSlotScopeId) {
    context.pushStringPart(createSimpleExpression(`_scopeId`, false))
  }

  // close open tag
  context.pushStringPart(`>`)

  const rawChildren = rawChildrenMap.get(node)
  if (rawChildren) {
    context.pushStringPart(rawChildren)
  } else if (node.children.length) {
    processChildren(node, context)
  }

  if (!isVoidTag(node.tag)) {
    // push closing tag
    context.pushStringPart(`</${node.tag}>`)
  }
}

  const renderCall = node.ssrCodegenNode!

  // has fallback content
  if (node.children.length) {
    const fallbackRenderFn = createFunctionExpression([])
    fallbackRenderFn.body = processChildrenAsStatement(node, context)
    // _renderSlot(slots, name, props, fallback, ...)
    renderCall.arguments[3] = fallbackRenderFn
  }

  // Forwarded <slot/>. Merge slot scope ids
  if (context.withSlotScopeId) {
    const slotScopeId = renderCall.arguments[6]
    renderCall.arguments[6] = slotScopeId
      ? `${slotScopeId as string} + _scopeId`
      : `_scopeId`
  }

  context.pushStatement(node.ssrCodegenNode!)
}

  return (): void => {
    if (node.children.length) {
      const wipEntry: WIPEntry = {
        slotsExp: null!, // to be immediately set
        wipSlots: [],
      }
      wipMap.set(node, wipEntry)
      wipEntry.slotsExp = buildSlots(
        node,
        context,
        (_props, _vForExp, children, loc) => {
          const fn = createFunctionExpression(
            [],
            undefined, // no return, assign body later
            true, // newline
            false, // suspense slots are not treated as normal slots
            loc,
          )
          wipEntry.wipSlots.push({
            fn,
            children,
          })
          return fn
        },
      ).slots
    }
  }
}

  // complete wip slots with ssr code
  const wipEntry = wipMap.get(node)
  if (!wipEntry) {
    return
  }
  const { slotsExp, wipSlots } = wipEntry
  for (let i = 0; i < wipSlots.length; i++) {
    const slot = wipSlots[i]
    slot.fn.body = processChildrenAsStatement(slot, context)
  }
  // _push(ssrRenderSuspense(slots))
  context.pushStatement(
    createCallExpression(context.helper(SSR_RENDER_SUSPENSE), [
      `_push`,
      slotsExp,
    ]),
  )
}

  const targetProp = findProp(node, 'to')
  if (!targetProp) {
    context.onError(
      createSSRCompilerError(SSRErrorCodes.X_SSR_NO_TELEPORT_TARGET, node.loc),
    )
    return
  }

  let target: ExpressionNode | undefined
  if (targetProp.type === NodeTypes.ATTRIBUTE) {
    target =
      targetProp.value && createSimpleExpression(targetProp.value.content, true)
  } else {
    target = targetProp.exp
  }
  if (!target) {
    context.onError(
      createSSRCompilerError(
        SSRErrorCodes.X_SSR_NO_TELEPORT_TARGET,
        targetProp.loc,
      ),
    )
    return
  }

  const disabledProp = findProp(node, 'disabled', false, true /* allow empty */)
  const disabled = disabledProp
    ? disabledProp.type === NodeTypes.ATTRIBUTE
      ? `true`
      : disabledProp.exp || `false`
    : `false`

  const contentRenderFn = createFunctionExpression(
    [`_push`],
    undefined, // Body is added later
    true, // newline
    false, // isSlot
    node.loc,
  )
  contentRenderFn.body = processChildrenAsStatement(node, context)
  context.pushStatement(
    createCallExpression(context.helper(SSR_RENDER_TELEPORT), [
      `_push`,
      contentRenderFn,
      target,
      disabled,
      `_parent`,
    ]),
  )
}

  return (): void => {
    const appear = findProp(node, 'appear', false, true)
    wipMap.set(node, !!appear)
  }
}

  // #5351: filter out comment children inside transition
  node.children = node.children.filter(c => c.type !== NodeTypes.COMMENT)

  const appear = wipMap.get(node)
  if (appear) {
    context.pushStringPart(`<template>`)
    processChildren(node, context, false, true)
    context.pushStringPart(`</template>`)
  } else {
    processChildren(node, context, false, true)
  }
}

  return (): void => {
    const tag = findProp(node, 'tag')
    if (tag) {
      const otherProps = node.props.filter(p => p !== tag)
      const { props, directives } = buildProps(
        node,
        context,
        otherProps,
        true /* isComponent */,
        false /* isDynamicComponent */,
        true /* ssr (skip event listeners) */,
      )
      let propsExp = null
      if (props || directives.length) {
        propsExp = createCallExpression(context.helper(SSR_RENDER_ATTRS), [
          buildSSRProps(props, directives, context),
        ])
      }
      wipMap.set(node, {
        tag,
        propsExp,
        scopeId: context.scopeId || null,
      })
    }
  }
}

  const entry = wipMap.get(node)
  if (entry) {
    const { tag, propsExp, scopeId } = entry
    if (tag.type === NodeTypes.DIRECTIVE) {
      // dynamic :tag
      context.pushStringPart(`<`)
      context.pushStringPart(tag.exp!)
      if (propsExp) {
        context.pushStringPart(propsExp)
      }
      if (scopeId) {
        context.pushStringPart(` ${scopeId}`)
      }
      context.pushStringPart(`>`)

      processChildren(
        node,
        context,
        false,
        /**
         * TransitionGroup has the special runtime behavior of flattening and
         * concatenating all children into a single fragment (in order for them to
         * be patched using the same key map) so we need to account for that here
         * by disabling nested fragment wrappers from being generated.
         */
        true,
        /**
         * TransitionGroup filters out comment children at runtime and thus
         * doesn't expect comments to be present during hydration. We need to
         * account for that by disabling the empty comment that is otherwise
         * rendered for a falsy v-if that has no v-else specified. (#6715)
         */
        true,
      )
      context.pushStringPart(`</`)
      context.pushStringPart(tag.exp!)
      context.pushStringPart(`>`)
    } else {
      // static tag
      context.pushStringPart(`<${tag.value!.content}`)
      if (propsExp) {
        context.pushStringPart(propsExp)
      }
      if (scopeId) {
        context.pushStringPart(` ${scopeId}`)
      }
      context.pushStringPart(`>`)
      processChildren(node, context, false, true, true)
      context.pushStringPart(`</${tag.value!.content}>`)
    }
  } else {
    // fragment
    processChildren(node, context, true, true, true)
  }
}

  const needFragmentWrapper =
    !disableNestedFragments &&
    (node.children.length !== 1 || node.children[0].type !== NodeTypes.ELEMENT)
  const renderLoop = createFunctionExpression(
    createForLoopParams(node.parseResult),
  )
  renderLoop.body = processChildrenAsStatement(
    node,
    context,
    needFragmentWrapper,
  )
  // v-for always renders a fragment unless explicitly disabled
  if (!disableNestedFragments) {
    context.pushStringPart(`<!--[-->`)
  }
  context.pushStatement(
    createCallExpression(context.helper(SSR_RENDER_LIST), [
      node.source,
      renderLoop,
    ]),
  )
  if (!disableNestedFragments) {
    context.pushStringPart(`<!--]-->`)
  }
}

  const [rootBranch] = node.branches
  const ifStatement = createIfStatement(
    rootBranch.condition!,
    processIfBranch(rootBranch, context, disableNestedFragments),
  )
  context.pushStatement(ifStatement)

  let currentIf = ifStatement
  for (let i = 1; i < node.branches.length; i++) {
    const branch = node.branches[i]
    const branchBlockStatement = processIfBranch(
      branch,
      context,
      disableNestedFragments,
    )
    if (branch.condition) {
      // else-if
      currentIf = currentIf.alternate = createIfStatement(
        branch.condition,
        branchBlockStatement,
      )
    } else {
      // else
      currentIf.alternate = branchBlockStatement
    }
  }

  if (!currentIf.alternate && !disableComment) {
    currentIf.alternate = createBlockStatement([
      createCallExpression(`_push`, ['`<!---->`']),
    ])
  }
}

  const { children } = branch
  const needFragmentWrapper =
    !disableNestedFragments &&
    (children.length !== 1 || children[0].type !== NodeTypes.ELEMENT) &&
    // optimize away nested fragments when the only child is a ForNode
    !(children.length === 1 && children[0].type === NodeTypes.FOR)
  return processChildrenAsStatement(branch, context, needFragmentWrapper)
}

  const value = findProp(node, 'value')
  if (value) {
    context.onError(
      createDOMCompilerError(
        DOMErrorCodes.X_V_MODEL_UNNECESSARY_VALUE,
        value.loc,
      ),
    )
  }
}

  if (plainNode.tag === 'option') {
    if (plainNode.props.findIndex(p => p.name === 'selected') === -1) {
      const value = findValueBinding(plainNode)
      plainNode.ssrCodegenNode!.elements.push(
        createConditionalExpression(
          createCallExpression(context.helper(SSR_INCLUDE_BOOLEAN_ATTR), [
            createConditionalExpression(
              createCallExpression(`Array.isArray`, [model]),
              createCallExpression(context.helper(SSR_LOOSE_CONTAIN), [
                model,
                value,
              ]),
              createCallExpression(context.helper(SSR_LOOSE_EQUAL), [
                model,
                value,
              ]),
            ),
          ]),
          createSimpleExpression(' selected', true),
          createSimpleExpression('', true),
          false /* no newline */,
        ),
      )
    }
  } else if (plainNode.tag === 'optgroup') {
    processSelectChildren(plainNode.children)
  }
}

  children.forEach(child => {
    if (child.type === NodeTypes.ELEMENT) {
      processOption(child as PlainElementNode)
    } else if (child.type === NodeTypes.FOR) {
      processSelectChildren(child.children)
    } else if (child.type === NodeTypes.IF) {
      child.branches.forEach(b => processSelectChildren(b.children))
    }
  })
}

  bench('create computed', () => {
    computed(() => 100)
  })

  {
    const v = ref(100)
    computed(() => v.value * 2)
    let i = 0
    bench("write ref, don't read computed (without effect)", () => {
      v.value = i++
    })
  }

  {
    const v = ref(100)
    const c = computed(() => {
      return v.value * 2
    })
    effect(() => c.value)
    let i = 0
    bench("write ref, don't read computed (with effect)", () => {
      v.value = i++
    })
  }

  {
    const v = ref(100)
    const c = computed(() => {
      return v.value * 2
    })
    let i = 0
    bench('write ref, read computed (without effect)', () => {
      v.value = i++
      c.value
    })
  }

  {
    const v = ref(100)
    const c = computed(() => {
      return v.value * 2
    })
    effect(() => c.value)
    let i = 0
    bench('write ref, read computed (with effect)', () => {
      v.value = i++
      c.value
    })
  }

  {
    const v = ref(100)
    const computeds: ComputedRef<number>[] = []
    for (let i = 0, n = 1000; i < n; i++) {
      const c = computed(() => {
        return v.value * 2
      })
      computeds.push(c)
    }
    let i = 0
    bench("write ref, don't read 1000 computeds (without effect)", () => {
      v.value = i++
    })
  }

  {
    const v = ref(100)
    const computeds: ComputedRef<number>[] = []
    for (let i = 0, n = 1000; i < n; i++) {
      const c = computed(() => {
        return v.value * 2
      })
      effect(() => c.value)
      computeds.push(c)
    }
    let i = 0
    bench(
      "write ref, don't read 1000 computeds (with multiple effects)",
      () => {
        v.value = i++
      },
    )
  }

  {
    const v = ref(100)
    const computeds: ComputedRef<number>[] = []
    for (let i = 0, n = 1000; i < n; i++) {
      const c = computed(() => {
        return v.value * 2
      })
      computeds.push(c)
    }
    effect(() => {
      for (let i = 0; i < 1000; i++) {
        computeds[i].value
      }
    })
    let i = 0
    bench("write ref, don't read 1000 computeds (with single effect)", () => {
      v.value = i++
    })
  }

  {
    const v = ref(100)
    const computeds: ComputedRef<number>[] = []
